/* IncidentMapper.getIncidentStatusSummaryByDate - 상태별 건수 집계 (일자 기준) */ SELECT IFNULL(SUM(CASE WHEN status_cd = 'STS001' THEN 1 ELSE 0 END), 0) AS received_cnt, IFNULL(SUM(CASE WHEN status_cd = 'STS002' THEN 1 ELSE 0 END), 0) AS processing_cnt, IFNULL(SUM(CASE WHEN status_cd = 'STS003' THEN 1 ELSE 0 END), 0) AS completed_cnt, IFNULL(SUM(CASE WHEN status_cd = 'STS004' THEN 1 ELSE 0 END), 0) AS canceled_cnt, COUNT(*) AS total_cnt FROM incident
( site_cd IN
#{siteCd} OR report_no like 'UN%')
AND site_cd = #{siteCd}
AND report_date >= STR_TO_DATE(CONCAT(#{todayDt}, ' 00:00:00'), '%Y-%m-%d %H:%i:%s') AND report_date < STR_TO_DATE(CONCAT(#{todayDt}, ' 00:00:00'), '%Y-%m-%d %H:%i:%s') + INTERVAL 1 DAY

