/* IncidentMapper.updateInCident - 사고접수 수정 */
UPDATE incident
SET status_cd = #{statusCd}
    , intake_method_cd = #{intakeMethodCd}
    , process_note = #{processNote}
    , addr = #{addr}

        , cell_phone = HEX(AES_ENCRYPT(#{cellPhone}, 'RSOS'))


        , img_path = #{imgPath}


        , img_path = null


        , img_name = #{imgName}


        , img_name = null


        , site_cd = #{siteCd}


        , ocr_read_km = #{ocrReadKm}


        , lat = #{lat}


        , lng = #{lng}

    , manager_id = #{managerId}
    , update_datetime = NOW()
WHERE report_no = #{reportNo}

