/* IncidentMapper.selectIncidentList - 사고접수 조회 */ SELECT d.site_name , a.report_no , a.report_date , a.update_datetime , a.addr , CONVERT(AES_DECRYPT(UNHEX(a.cell_phone), 'RSOS') USING utf8) AS cell_phone , a.status_cd , b.cd_code_nm AS statusNm , c.cd_code_nm AS intakeMethodNm , a.manager_id , a.process_note FROM incident a LEFT JOIN cd_common b ON a.status_cd = b.cd_code AND b.cd_div = '002' AND b.use_yn = 'Y' LEFT JOIN cd_common c ON a.intake_method_cd = c.cd_code AND c.cd_div = '001' AND c.use_yn = 'Y' LEFT JOIN site_info d ON a.site_cd = d.site_cd AND d.del_yn = 'N' WHERE 1=1
ORDER BY a.report_date DESC
LIMIT #{offset}, #{pageSize}

